import React, { useEffect, useState } from "react";
import {
  Box, Typography, Grid, Card, CircularProgress, Alert, Table,
  TableBody, TableCell, TableContainer, TableHead, TableRow, Paper, Button, Tabs, Tab
} from "@mui/material";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const API = process.env.REACT_APP_API_URL || "http://localhost:5000";

const AdminDashboard = () => {
  const [users, setUsers] = useState([]);
  const [captains, setCaptains] = useState([]);
  const [pendingCaptains, setPendingCaptains] = useState([]);
  const [rides, setRides] = useState([]);
  const [overview, setOverview] = useState({
    usersCount: 0,
    ridersCount: 0,
    captainsCount: 0,
    pendingCaptainsCount: 0,
    ridesCount: 0,
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [tab, setTab] = useState("overview");

  const navigate = useNavigate();
  const token = localStorage.getItem("token");

  const fetchData = async () => {
    setLoading(true); setError("");
    try {
      const headers = { Authorization: `Bearer ${token}` };
      const [overviewRes, usersRes, captainsRes, pendingRes, ridesRes] = await Promise.all([
        axios.get(`${API}/api/admin/overview`, { headers }),
        axios.get(`${API}/api/admin/users`, { headers }),
        axios.get(`${API}/api/admin/captains`, { headers }),
        axios.get(`${API}/api/admin/pending-captains`, { headers }),
        axios.get(`${API}/api/admin/rides`, { headers }),
      ]);
      setOverview(overviewRes.data || {});
      setUsers(usersRes.data || []);
      setCaptains(captainsRes.data || []);
      setPendingCaptains(pendingRes.data || []);
      setRides(ridesRes.data || []);
    } catch (err) {
      console.error(err);
      setError(err.response?.data?.message || "Failed to fetch data");
    } finally { setLoading(false); }
  };

  useEffect(() => { fetchData(); }, []); // eslint-disable-line

  const handleApprove = async (id) => {
    try {
      await axios.put(`${API}/api/admin/captain/${id}/approve`, {}, { headers: { Authorization: `Bearer ${token}` }});
      fetchData();
    } catch (err) { setError(err.response?.data?.message || "Failed to approve captain"); }
  };

  const handleReject = async (id) => {
    try {
      await axios.put(`${API}/api/admin/captain/${id}/reject`, {}, { headers: { Authorization: `Bearer ${token}` }});
      fetchData();
    } catch (err) { setError(err.response?.data?.message || "Failed to reject captain"); }
  };

  const handleLogout = () => { localStorage.removeItem("token"); navigate("/admin-login"); };

  const renderClickableCell = (name, type, id) => (
    <Button variant="text" onClick={() => navigate(`/admin/${type}/${id}`)}>{name}</Button>
  );

  return (
    <Box p={4}>
      <Box display="flex" justifyContent="space-between" alignItems="center" mb={3}>
        <Typography variant="h4">Rider App - Admin Dashboard</Typography>
        <Button variant="contained" color="error" onClick={handleLogout}>Logout</Button>
      </Box>

      <Tabs value={tab} onChange={(e, val) => setTab(val)} sx={{ mb: 3 }}>
        <Tab label="Overview" value="overview" />
        <Tab label="Users" value="users" />
        <Tab label="Captains" value="captains" />
        <Tab label="Pending Captains" value="pending" />
        <Tab label="Rides" value="rides" />
      </Tabs>

      {loading && <Box display="flex" justifyContent="center" my={2}><CircularProgress /></Box>}
      {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

      {tab === "overview" && (
        <Grid container spacing={3}>
          {Object.entries(overview).map(([key, value]) => (
            <Grid item xs={12} sm={6} md={3} key={key}>
              <Card sx={{ textAlign: "center", py: 3 }}>
                <Typography variant="h6">{key.replace(/Count$/, "").replace(/([A-Z])/g, " $1")}</Typography>
                <Typography variant="h4">{value}</Typography>
              </Card>
            </Grid>
          ))}
        </Grid>
      )}

      {/* Users Table */}
      {tab === "users" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell><b>Full Name</b></TableCell>
                <TableCell><b>Email</b></TableCell>
                <TableCell><b>Mobile</b></TableCell>
                <TableCell><b>Role</b></TableCell>
                <TableCell><b>Status</b></TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {users.length > 0 ? users.map(u => (
                <TableRow key={u._id}>
                  <TableCell>{renderClickableCell(u.fullName, "rider", u._id)}</TableCell>
                  <TableCell>{u.email}</TableCell>
                  <TableCell>{u.mobile}</TableCell>
                  <TableCell>{u.role}</TableCell>
                  <TableCell>{u.approvalStatus || "-"}</TableCell>
                </TableRow>
              )) : (
                <TableRow><TableCell colSpan={5} align="center">No users found</TableCell></TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* Captains Table */}
      {tab === "captains" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Documents</TableCell>
                <TableCell>Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {captains.length > 0 ? captains.map(c => (
                <TableRow key={c._id}>
                  <TableCell>{renderClickableCell(c.fullName, "captain", c._id)}</TableCell>
                  <TableCell>{c.email}</TableCell>
                  <TableCell>
                    {c.documents?.map((doc, i) => (
                      <Box key={i}>
                        <a href={doc.url} target="_blank" rel="noreferrer">{doc.name}</a>
                      </Box>
                    )) || "-"}
                  </TableCell>
                  <TableCell>{c.status}</TableCell>
                </TableRow>
              )) : (
                <TableRow><TableCell colSpan={4} align="center">No captains found</TableCell></TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* Pending Captains */}
      {tab === "pending" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Name</TableCell>
                <TableCell>Email</TableCell>
                <TableCell>Status</TableCell>
                <TableCell>Actions</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {pendingCaptains.length > 0 ? pendingCaptains.map(p => (
                <TableRow key={p._id}>
                  <TableCell>{p.fullName}</TableCell>
                  <TableCell>{p.email}</TableCell>
                  <TableCell>{p.status}</TableCell>
                  <TableCell>
                    <Button size="small" variant="contained" color="success" sx={{ mr: 1 }}
                      onClick={() => handleApprove(p._id)}>Approve</Button>
                    <Button size="small" variant="contained" color="error"
                      onClick={() => handleReject(p._id)}>Reject</Button>
                  </TableCell>
                </TableRow>
              )) : (
                <TableRow><TableCell colSpan={4} align="center">No pending captains</TableCell></TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      {/* Rides */}
      {tab === "rides" && (
        <TableContainer component={Paper}>
          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Rider</TableCell>
                <TableCell>Captain</TableCell>
                <TableCell>Pickup</TableCell>
                <TableCell>Drop</TableCell>
                <TableCell>Fare</TableCell>
                <TableCell>Status</TableCell>
              </TableRow>
            </TableHead>
            <TableBody>
              {rides.length > 0 ? rides.map(r => (
                <TableRow key={r._id}>
                  <TableCell>{r.rider?.fullName || "-"}</TableCell>
                  <TableCell>{r.captain?.fullName || "-"}</TableCell>
                  <TableCell>{r.pickup}</TableCell>
                  <TableCell>{r.drop}</TableCell>
                  <TableCell>{r.fare}</TableCell>
                  <TableCell>{r.status}</TableCell>
                </TableRow>
              )) : (
                <TableRow><TableCell colSpan={6} align="center">No rides found</TableCell></TableRow>
              )}
            </TableBody>
          </Table>
        </TableContainer>
      )}

    </Box>
  );
};

export default AdminDashboard;
